import { Component, OnInit } from '@angular/core';
import { CategoriaService } from '../../services/categoria.service';
import { Categoria } from '../../models/categoria.model';

@Component({
  selector: 'app-categorias',
  templateUrl: './categorias.component.html',
  styleUrls: ['./categorias.component.css']
})
export class CategoriasComponent implements OnInit {
  categorias: Categoria[] = [];
  cargando = true;
  error = '';

  constructor(private categoriaService: CategoriaService) { }

  ngOnInit(): void {
    this.categoriaService.getAll().subscribe({
      next: (data) => { this.categorias = data; this.cargando = false; },
      error: () => { this.error = 'Error al cargar categorías.'; this.cargando = false; }
    });
  }
}
<div class="container mt-4">
  <h2><i class="bi bi-tags"></i> Categorías</h2>
  <div *ngIf="cargando" class="text-center"><div class="spinner-border text-primary"></div></div>
  <div *ngIf="error" class="alert alert-danger">{{ error }}</div>
  <div class="row mt-4" *ngIf="!cargando && !error">
    <div class="col-md-4 mb-3" *ngFor="let categoria of categorias">
      <div class="card">
        <div class="card-body">
          <h5 class="card-title"><i class="bi bi-tag-fill text-primary"></i> {{ categoria.nombre }}</h5>
          <p class="card-text text-muted">{{ categoria.descripcion }}</p>
          <a routerLink="/productos" class="btn btn-outline-primary">Ver Productos</a>
        </div>
      </div>
    </div>
  </div>
</div>
